// Date formatting function: converts date to "9th May, 2020" format
const formatDate = (dateString) => {
  if (!dateString) return '';

  // Parse the date - supports formats like: 9/05/2020, 09/05/2020, 9-05-2020, 2020-05-09
  let day, month, year;

  // Try to parse common formats
  if (dateString.includes('/')) {
    const parts = dateString.split('/');
    // Assume DD/MM/YYYY (most common)
    day = parseInt(parts[0], 10);
    month = parseInt(parts[1], 10);
    year = parseInt(parts[2], 10);
  } else if (dateString.includes('-')) {
    const parts = dateString.split('-');
    // Check if it's YYYY-MM-DD format
    if (parts[0].length === 4) {
      year = parseInt(parts[0], 10);
      month = parseInt(parts[1], 10);
      day = parseInt(parts[2], 10);
    } else {
      // Assume DD-MM-YYYY
      day = parseInt(parts[0], 10);
      month = parseInt(parts[1], 10);
      year = parseInt(parts[2], 10);
    }
  } else {
    return dateString; // Return as-is if format not recognized
  }

  // Validate parsed values
  if (isNaN(day) || isNaN(month) || isNaN(year)) {
    return dateString;
  }

  // Month names
  const monthNames = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
  ];

  // Add ordinal suffix to day
  const getOrdinalSuffix = (d) => {
    if (d > 3 && d < 21) return 'th'; // 4th-20th
    switch (d % 10) {
      case 1: return 'st';
      case 2: return 'nd';
      case 3: return 'rd';
      default: return 'th';
    }
  };

  const monthName = monthNames[month - 1];
  const ordinalDay = day + getOrdinalSuffix(day);

  return `${ordinalDay} ${monthName}, ${year}`;
};

